w:r.w:t:
model ProjectFinancePlan { id String @id @default(cuid()) projectId String version Int @default(1) cutoffDate DateTime @db.Timestamptz // "-ĐC - 31 03 2026" status PlanStatus @default(DRAFT) // DRAFT / APPROVED / SUPERSEDED
// Contract summary (from sheet "Dòng tiền và dự toán gốc") customerId String? scopeDescription String? @db.Text contractValueVnd Decimal @db.Decimal(18, 2) contractValueCcy String? // USD / EUR contractValueFx Decimal? @db.Decimal(15, 2) paymentTermDays Int // NET 45 grossMarginPct Decimal @db.Decimal(5, 4)
// Audit createdById String approvedById String? approvedAt DateTime? createdAt DateTime @default(now()) @db.Timestamptz
project Project @relation(fields: [projectId], references: [id]) budgetLines ProjectBudgetLine[] monthlyCashflow ProjectCashflowMonthly[] milestones ContractPaymentMilestone[]
@@unique([projectId, version]) @@index([status, cutoffDate]) }

model ProjectBudgetLine { id String @id @default(cuid()) planId String parentId String? // hierarchical: A → 1 → 1.1 code String // "VTC01", "PC", "DVT" — mã dự toán từ Excel sectionType BudgetSection // MATERIAL / LABOUR / SUBCONTRACT / OVERHEAD / GUARANTEE / VAT / CONTINGENCY itemName String unit String? // kg / m2 / chuyến quantity Decimal? @db.Decimal(18, 4) unitPrice Decimal? @db.Decimal(18, 4) amountVnd Decimal @db.Decimal(18, 2) percentOfTotal Decimal? @db.Decimal(5, 4)
// Optional dimensional links (allow fact-based allocation) materialId String? // from ibshi1 Material master activityCode String? // from BOM (Tekla operation) costCenterId String?
plan ProjectFinancePlan @relation(fields: [planId], references: [id]) parent ProjectBudgetLine? @relation("Hierarchy", fields: [parentId], references: [id]) children ProjectBudgetLine[] @relation("Hierarchy")
@@index([planId, sectionType]) @@index([planId, code]) }
enum BudgetSection { MATERIAL LABOUR SUBCONTRACT OVERHEAD GUARANTEE VAT CONTINGENCY }

model ProjectCashflowMonthly { id String @id @default(cuid()) planId String periodYm String // "202604" (YYYYMM) periodIndex Int // 1 = Tháng 6 (contract start), 2, 3...
// Outflow (Dòng tiền ra) — grouped by section outflowMaterial Decimal @db.Decimal(18, 2) @default(0) outflowLabour Decimal @db.Decimal(18, 2) @default(0) outflowSubcontract Decimal @db.Decimal(18, 2) @default(0) outflowOverhead Decimal @db.Decimal(18, 2) @default(0) outflowGuarantee Decimal @db.Decimal(18, 2) @default(0) outflowVat Decimal @db.Decimal(18, 2) @default(0) outflowTotal Decimal @db.Decimal(18, 2)
// Inflow (Dòng tiền vào) — linked to milestones inflowTotal Decimal @db.Decimal(18, 2) @default(0)
// Computed netCashflow Decimal @db.Decimal(18, 2) ownEquityPortion Decimal @db.Decimal(18, 2) @default(0) // Vốn tự có tự thu xếp requiredLoanAmount Decimal @db.Decimal(18, 2) @default(0) // Hạn mức vay vốn estimatedInterest Decimal @db.Decimal(18, 2) @default(0) // Lãi vay
plan ProjectFinancePlan @relation(fields: [planId], references: [id])
@@unique([planId, periodYm]) @@index([planId, periodIndex]) }

model ContractPaymentMilestone { id String @id @default(cuid()) planId String projectId String
name String // "Tạm ứng Hợp đồng" / "Sau khi mua đủ vật tư" / "Giao U1" / "Giao U2" / "Hoàn thành" code String // TUE / MV / U1 / U2 / HT — for short identifier percentOfContract Decimal @db.Decimal(5, 4) amountVndPlan Decimal @db.Decimal(18, 2) amountCcyPlan Decimal? @db.Decimal(15, 2) plannedMonthYm String // when we expect to invoice triggerCondition String @db.Text // "Sau khi NCC giao đủ vật tư", "DO Packaging U1"
// Actuals actualInvoiceId String? @unique // → Invoice (ibshi1 existing) actualDate DateTime? actualAmountVnd Decimal? @db.Decimal(18, 2) status MilestoneStatus @default(PLANNED) // PLANNED / INVOICED / COLLECTED
plan ProjectFinancePlan @relation(fields: [planId], references: [id]) project Project @relation(fields: [projectId], references: [id])
@@index([projectId, status]) }

model LoanDrawdown { id String @id @default(cuid()) loanContractId String projectId String drawdownNo String // "Vay 095 VP bank 04 03 2026 đi 10 03 2026" requestDate DateTime @db.Timestamptz executionDate DateTime? @db.Timestamptz // ngày "đi" = bank disburses totalAmountVnd Decimal @db.Decimal(18, 2) totalAmountCcy Decimal? @db.Decimal(15, 2)
status DrawdownStatus @default(DRAFT) // DRAFT / SUBMITTED / APPROVED_BY_BANK / EXECUTED / REJECTED createdById String approvedById String? approvedAt DateTime?
// Integration trace misaVoucherId String? misaPostedAt DateTime?
loanContract LoanContract @relation(fields: [loanContractId], references: [id]) project Project @relation(fields: [projectId], references: [id]) lines DrawdownBeneficiaryLine[]
@@unique([drawdownNo]) @@index([projectId, status]) }
model LoanLiquidation { id String @id @default(cuid()) loanContractId String projectId String liquidationNo String // "Giải toả VPB 095- 03/12/2025 đi 10/12/2025" // ...identical shape to LoanDrawdown — status enum LiquidationStatus requestDate DateTime @db.Timestamptz executionDate DateTime? @db.Timestamptz totalAmountVnd Decimal @db.Decimal(18, 2) status LiquidationStatus @default(DRAFT) createdById String approvedById String? approvedAt DateTime? misaVoucherId String?
loanContract LoanContract @relation(fields: [loanContractId], references: [id]) project Project @relation(fields: [projectId], references: [id]) lines DrawdownBeneficiaryLine[]
@@unique([liquidationNo]) @@index([projectId, status]) }
enum DrawdownStatus { DRAFT SUBMITTED APPROVED_BY_BANK EXECUTED REJECTED } enum LiquidationStatus { DRAFT SUBMITTED APPROVED_BY_BANK EXECUTED REJECTED }

model DrawdownBeneficiaryLine { id String @id @default(cuid()) drawdownId String? liquidationId String?
sequenceNo Int vendorId String // → Vendor (ibshi1) invoiceId String? // → Invoice if matched invoiceNumber String // "6775", "00000236" — từ Excel invoiceDate DateTime? @db.Timestamptz invoiceAmountVnd Decimal @db.Decimal(18, 2) // "Giá trị chứng từ" amountFundedVnd Decimal @db.Decimal(18, 2) // "Giá trị cho vay lần này"
beneficiaryBankAcct String // STK (mã số tài khoản NCC) beneficiaryBankName String // "VP bank", "MB Long Biên" contentDescription String? // "Thép", "Mạ kẽm"
// Cost bucket (from sheet "Chi tiết thanh toán các đợt") costBucket CostBucket? // STEEL / MATERIAL_AUX / WELDING / PAINT / OVERHEAD / ...
drawdown LoanDrawdown? @relation(fields: [drawdownId], references: [id]) liquidation LoanLiquidation? @relation(fields: [liquidationId], references: [id]) vendor Vendor @relation(fields: [vendorId], references: [id]) invoice Invoice? @relation(fields: [invoiceId], references: [id])
@@index([drawdownId]) @@index([liquidationId]) @@index([vendorId]) }
enum CostBucket { STEEL // Thép MATERIAL_AUX // Vật liệu phụ WELDING // Vật liệu hàn PAINT // Sơn INSULATION // Bảo ôn PACKAGING // Vật tư đóng kiện, biện pháp LABOUR // Nhân công SUBCONTRACT // Thầu phụ OVERHEAD // Chi phí quản lý INTEREST // Chi phí lãi vay CONTINGENCY // Dự phòng }
